query:
-- Update menu categories to English
UPDATE menuCategories SET name = 'Main' WHERE name = '메인';
UPDATE menuCategories SET name = 'Side' WHERE name = '사이드';
UPDATE menuCategories SET name = 'Drink' WHERE name = '음료';

-- Update menu items to English
UPDATE menuItems SET name = 'Dosirock\'s Signature Bibimbap', description = 'The authenticity of Korean Bibimbap, a flavorful blend of assorted vegetables and premium beef mince, crowned with a sunny-side-up egg, and enhanced with our house-made Gochujang spicy sauce and fragrant Sesame oil.' WHERE name LIKE '%비빔밥%';

UPDATE menuItems SET name = 'Beef Bibimbap', description = 'Tender beef mixed with fresh vegetables and rice, topped with a sunny-side-up egg and our signature Gochujang sauce.' WHERE name = 'Beef Bibimbap';

UPDATE menuItems SET name = 'Vegetarian Bibimbap', description = 'A delicious vegetarian option featuring assorted fresh vegetables, rice, and our house-made Gochujang sauce.' WHERE name = 'Vegetarian Bibimbap';

UPDATE menuItems SET name = 'Dosirock Korean Lunch Box', description = 'Korean Lunch Tray features your choice of a main dish served with a selection of four daily side dishes. For group orders of 10 or more, please contact us before placing your order.' WHERE name LIKE '%도시락%';

UPDATE menuItems SET name = 'Spicy Pork on Rice', description = 'Savor the fiery flavors of marinated and pan-fried pork, smothered in our secret house-made Korean spicy sauce served over a bed of steaming rice, and accompanied by a crisp green salad.' WHERE name LIKE '%제육덮밥%';

UPDATE menuItems SET name = 'Korean Spicy Chicken on Rice', description = 'Indulge in pan-fried chicken coated in our secret house-made Korean spicy sauce, served on a bed of steaming rice, and accompanied by a crisp green salad.' WHERE name LIKE '%닭갈비덮밥%';

UPDATE menuItems SET name = 'Sweet Chili Chicken on Rice', description = 'Delight in deep-fried chicken, generously coated in a harmonious blend of sweet and chili sauces, served on a bed of steaming rice, and accompanied by a crisp green salad.' WHERE name LIKE '%양념치킨덮밥%';

UPDATE menuItems SET name = 'Beef Bulgogi on Rice', description = 'Savor the rich flavors of marinated and grilled Bulgogi beef served over a bed of steaming rice, and accompanied by a crisp green salad.' WHERE name LIKE '%불고기덮밥%';

UPDATE menuItems SET name = 'Vegetarian Japchae', description = 'Delight in the delectable blend of Kumara starch noodles in Japchae, stir-fried vegetables, and a side of green salad, all beautifully finished with a drizzle of fragrant sesame oil and a sprinkle of sesame seeds.' WHERE name LIKE '%잡채%' AND name NOT LIKE '%불고기%';

UPDATE menuItems SET name = 'Beef Bulgogi Japchae', description = 'Delight in the harmonious fusion of Kumara starch noodles, tender beef bulgogi, stir-fried vegetables, and a side of green salad, all beautifully finished with a drizzle of fragrant sesame oil and a sprinkle of sesame seeds.' WHERE name LIKE '%불고기잡채%';

UPDATE menuItems SET name = 'Roasted Eel on Rice', description = 'Experience the delectable taste of whole roasted eel, complemented with a side of fresh green salad, tangy pickled ginger, and a wedge of zesty lemon, all served on a fluffy bed of rice.' WHERE name LIKE '%장어%';

UPDATE menuItems SET name = 'Tuna Mayo Triangle Kimbap', description = 'Enjoy a savory blend of tuna and creamy mayo wrapped in triangular rice and seaweed. Try our crispy deep-fried option for an extra delightful treat.' WHERE name LIKE '%참치마요%';

UPDATE menuItems SET name = 'Beef Bulgogi Triangle Kimbap', description = 'Experience the rich flavors of tender beef Bulgogi nestled within the satisfying layers of rice and seaweed. Try our crispy deep-fried option for an extra delightful treat.' WHERE name LIKE '%불고기%' AND name LIKE '%삼각%';

UPDATE menuItems SET name = 'Spam Triangle Kimbap', description = 'Enjoy a classic favorite with Spam, a unique and tasty twist on traditional Kimbap. Try our crispy deep-fried option for an extra delightful treat.' WHERE name LIKE '%스팸%';

UPDATE menuItems SET name = 'Spicy Pork Triangle Kimbap', description = 'Satisfy your taste buds with deep-fried and Dosirock\'s secret seasoned spicy pork, skillfully rolled into a convenient triangular snack.' WHERE name LIKE '%제육%' AND name LIKE '%삼각%';

UPDATE menuItems SET name = 'Buldak Chicken Triangle Kimbap', description = 'For those seeking a fiery kick, our Buldak Samgak Kimbap is deep-fried and seasoned with Dosirock\'s secret seasoning, filled with intensely spicy ingredients for a taste explosion.' WHERE name LIKE '%불닭%';

